import { createContext, useContext } from "react";

import { tableVariants } from "./table.variants";

export type TableContext = {
  slots: ReturnType<typeof tableVariants>;
};

export const TableContext = createContext<null | TableContext>(null);

export const useTableContext = () => {
  const context = useContext(TableContext);
  if (!context) {
    throw new Error("useTableContext must be used within a Table.Root");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const tableVariants = tv({
  slots: {
    root: "table",
    header: "table__header",
    body: "table__body",
    footer: "table__footer",
    row: "table__row",
    head: "table__head",
    cell: "table__cell",
    caption: "table__caption",
  },
});

export type TableVariants = VariantProps<typeof tableVariants>;

.table {
  @apply w-full caption-bottom text-sm;
}

.table__header {
  @apply [&_tr]:border-b;
}

.table__body {
  @apply [&_tr:last-child]:border-0;
}

.table__footer {
  @apply bg-muted/50 border-t font-medium [&>tr]:last:border-b-0;
}

.table__row {
  @apply hover:bg-muted/50 data-[state=selected]:bg-muted border-b transition-colors;
}

.table__head {
  @apply text-muted-foreground h-10 px-2 text-left align-middle font-medium whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px];
}

.table__cell {
  @apply p-2 align-middle [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px];
}

.table__caption {
  @apply text-muted-foreground mt-4 text-sm;
}

import { TableBody } from "./table-body";
import { TableCaption } from "./table-caption";
import { TableCell } from "./table-cell";
import { TableFooter } from "./table-footer";
import { TableHead } from "./table-head";
import { TableHeader } from "./table-header";
import { TableRoot } from "./table-root";
import { TableRow } from "./table-row";

export const Table = {
  Body: TableBody,
  Caption: TableCaption,
  Cell: TableCell,
  Footer: TableFooter,
  Head: TableHead,
  Header: TableHeader,
  Root: TableRoot,
  Row: TableRow,
};

export {
  TableBody,
  TableCaption,
  TableCell,
  TableFooter,
  TableHead,
  TableHeader,
  TableRoot,
  TableRow,
};

export { TableContext, useTableContext } from "./table.context";

export { type TableVariants, tableVariants } from "./table.variants";
